VALUES
  ('disabled-64311456-moex-00295', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '甲於公告禁止設攤之某騎樓擺攤販售蔬果，遭警察以妨礙交通為由處罰， 下列敘述何者正確？', '["甲得騎樓所有權人同意設攤，不應處罰", "警察未處罰其他騎樓攤販，違反平等原則", "如甲取得市政府核發得於該騎樓擺攤之營業許可，不罰", "騎樓供人行走非車輛行駛道路，無妨礙車輛交通，不應處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00296', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '環境主管機關抽檢 A 公司放流水，發現未符合標準，爰裁處 A 罰鍰，同 時要求1個月內改善後再行檢查，下列敘述何者正確？', '["A得以事後改善已符合標準為由，請求撤銷原罰鍰之處罰", "A得主張無故意過失，故既不得裁處罰鍰，亦不得命其限期改善", "A得主張主管機關既裁處罰鍰，基於一事不二罰法理，不應再命其限期 改善", "A得請求主管機關指導建議合法放流水處置方法與程序"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00297', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '甲違反行政法上義務應受處罰，乙因該行為受有財產上利益而未受處罰 時，主管機關對於乙所受財產上利益價值，得如何處置？', '["追徵", "追繳", "沒入", "沒收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00298', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '甲因欠繳稅款致名下房屋遭行政執行分署查封，甲不服，依實務見解如何 處理？', '["甲聲明異議未果後，不得續行救濟", "甲聲明異議未果後，應踐行訴願程序，始得提起行政訴訟", "甲聲明異議未果後，得直接提起行政訴訟", "甲直接向普通法院請求救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00299', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '下列何者非屬即時強制措施？', '["主管機關對於意圖自殺之甲予以管束，否則不能達到救護其生命之目的", "乙家中之違章建築，經主管機關命拆除而不拆除，主管機關乃委請丙予 以拆除", "主管機關為預防危害之必要，將丁所有之武士刀予以扣留", "消防人員為撲滅戊家中火災，以破壞剪切除己住處大門，以利由己住處 頂樓對戊家中噴水救火"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00300', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依行政執行法規定扣留之物，其扣留期間不得逾 30 日。但扣留之原因未 消失時，得延長之，延長之期間最長不得逾多久？', '["20日", "1個月", "30日", "2個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00301', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '下列何種行政行為適用行政程序法之程序規定？', '["不起訴處分", "學生成績之評定", "交通違規之記點決定", "對公務員之申誡決定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00302', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '依政府資訊公開法規定，下列何者非屬應主動公開之政府資訊？', '["政府機關首長之電子信箱帳號", "政府採購契約書", "年度決算書", "赴國外考察報告書"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00303', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於行政程序法中聽證程序之敘述，下列何者錯誤？', '["舉行聽證應作成聽證紀錄", "作成限制或剝奪自由之行政處分前應經聽證程序", "對經聽證程序作行政處分不服者依法免除訴願及其先行程序", "行政機關舉行聽證前應以書面通知當事人及其他已知利害關係人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
  ('disabled-64311456-moex-00304', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '關於政府資訊公開之敘述，下列何者錯誤？', '["政府資訊中若有含限制公開事項且可得分割者，應就其他部分提供之", "政府機關就人民申請提供、更正或補充政府資訊所為之行政決定，其性 質為事實行為", "政府資訊公開有侵害個人隱私者，經當事人同意仍得公開", "政府資訊之公開若有礙於犯罪之偵查者，行政機關應拒絕公開"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL)
